const Q_ECONOMICS_2004=[{"id": "objective>Economics>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If budget deficits are financed by borrowing, the crowding-out effect can be offset by an increase in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rates</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The crowding-out effect refers to the situation where increased public sector spending replaces, or drives down, private sector spending. If budget deficits are financed by borrowing, it can lead to an increase in interest rates, which can discourage private investment. However, an increase in savings can offset the crowding-out effect because it increases the funds available for private investment.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The differences between payment and receipts for visible trade is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bilateral trade</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of trade shows relationship between visible export and import. It is the same as visible trade.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the causes of the present high rate of inflation in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increasing factor costs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate appreciation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing budget surplus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high capacity utilization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the causes of the present high rate of inflation in Nigeria is increasing factor costs. Inflation is the rate at which the general level of prices for goods and services is rising, and subsequently, purchasing power is falling. Factor costs refer to the cost of the inputs used in production, such as labor, capital, and materials. When these costs increase, producers often pass on the costs to consumers in the form of higher prices, leading to inflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major reason for having national development plans is to  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">involve people in national programmes  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">make government spend more on production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure that more citizens are involved in planning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure efficient use of available resources</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ensuring an efficient usage of the available resources that cut across a nation leads to a rapid development and optimum production since 'efficient' means getting maximum from a given input.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the importation of a commodity is limited to a definite quantity, the trade control means used is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quotas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devaluation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange control</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quota, by definition, is a restricted supply of a good or service. When the importation of a commodity is limited to a definite quantity, the trade control means used is known as quotas or quantitative restrictions. Import quotas are used to protect domestic industries.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of aggregate expenditure over full employment level of output is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">GNP gap </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> deflationary gap </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> recessionary gap   </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> inflationary gap</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An inflationary gap, in economics, is the amount by which the actual gross domestic product (GDP) exceeds potential full-employment GDP.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of shareholders in a private limited liability company ranges from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two to twenty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">two to fifty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">two to seven </div>", "<div style=\"font-family:Cambria;font-size:17px;\">two to three</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For private companies, the number of shareholders should not be more than 50 (counting joint holders of shares as 1 person and not counting any person in the employment of the company or of its subsidiary or any person who while previously in the employment of the company or of its subsidiary was and thereafter has continued to be a member of the company).</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is the government's plan to control aggregate demand by manipulating </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revenue and expenditure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand and supply of money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tastes and preferences of consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the structure of production and employment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is the taxation and expenditure policy of a government. The extent to which fiscal policy can be employed depends on what a government can observe of economic behavior.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The European Union was formed to  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">finance development projects in member nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote economic integration in non-member countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assist countries to achieve their economic goals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote free trade within member nations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The European Union policies aim to ensure the free movement of people, goods, services and capital within the internal market; enact legislation in justice and home affairs; and maintain common policies on trade, agriculture, fisheries and regional development.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tax levied on goods and services at each stage of production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">VAT </div>", "<div style=\"font-family:Cambria;font-size:17px;\">PAYE  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">surtax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ad valorem tax</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">VAT, or Value Added Tax, is a type of tax that is applied at each stage of production of a good or service. It is based on the increase in value of a product or service at each stage of production or distribution. Therefore, the correct answer is VAT.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country is said to have absolute advantage when she </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can sell to other countries without buying from them </div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a higher opportunity cost in the production of a good </div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a lower opportunity cost in the production of a good </div>", "<div style=\"font-family:Cambria;font-size:17px;\">can produce more of any good with fewer resources.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Absolute advantage is an early theory of international trade which state that one country enters into trade with another because it has greater productivity than that country in a particular industry or industries.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristic of a mixed economy is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic decisions are made by both the rich and the poor  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic activities are undertaken by both the public and private sectors  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the federal and the state governments undertake joint projects  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">both primary and secondary production are undertaken.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mixed economy is an economy combining the methods and goals of capitalism and socialism, particularly by encouraging the growth of the public sector.both government and private sector control the means of production and distribution of good and service in the economy.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to increase revenue, the seller of a commodity whose demand is fairly elastic is advised to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">retain price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce output </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce price</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">since consumer reacts to changes in price when demand is elastic.price must be reduced to increase revenue.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A large standard deviation is an indication of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a wide spread around the mean </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the difference between the highest  and the lowest values </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a wide difference between the mean and the mode  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the size of the sample</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard deviation measures the dispersion of values of a variable about its arithmetic mean that is calculated as the square root of the sum of the differences between each of those values and the arithmetic mean divided by the number of values minus one.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> In the diagram above, ST is the budget line while I, II, and III represent indifference curves. A rational consumer will choose to consume at point </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M </div>", "<div style=\"font-family:Cambria;font-size:17px;\">L </div>", "<div style=\"font-family:Cambria;font-size:17px;\">J  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">K </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Consumer will choose point L because this is the point at which the budget line is tangential to the indifference curve and here he maximizes satisfaction .</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in demand for a normal good means </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a movement along a given demand curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand changes as price changes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in the price elasticity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a shift in the demand curve </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It means that the demand for normal goods increases with an increase in the consumer's income or expansion of the economy (which generally will increase the income of the population). Normal goods demonstrate a higher income elasticity of demand than inferior goods.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final stage in the production process of any commodity involves its movement from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wholesaler to the retailer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retailer to the consumer  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retailer to the wholesaler </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producer to the wholesaler.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As in the chain of distribution; from the producer – wholesaler – retailer - final consumer. The production process is yet to be completed if the goods produced have not reached the final consumer.where the goods is passed by the retailer to the consumer.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the assumptions of ordinal utility in consumer behaviours is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">utility can only be ranked  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility rises continuously </div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility is measurable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers are irrational</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinalist school believes that utility cannot be measured but can be ranked i.e indicate whether utility is less, or more than.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In any set of data, the median represents the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">difference between the highest and the lowest values when arranged in ascending order </div>", "<div style=\"font-family:Cambria;font-size:17px;\">value that is most representative of the data </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mid-position when the values are arranged randomly. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mid-position when the values are arranged in ascending or descending order </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Median is the middle value (or arithmetic mean of the two middle values when there is an even number of values) of numbers arranged in order of magnitude.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Combination</td><td style=\"border:1px solid black;text-align:center;\">  Beans (Units)</td><td style=\"border:1px solid black;text-align:center;\">  Rice (Units)  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">K</td><td style=\"border:1px solid black;text-align:center;\"> 15</td><td style=\"border:1px solid black;text-align:center;\"> 19  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">L</td><td style=\"border:1px solid black;text-align:center;\"> 20</td><td style=\"border:1px solid black;text-align:center;\"> 17  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">M</td><td style=\"border:1px solid black;text-align:center;\"> 24</td><td style=\"border:1px solid black;text-align:center;\"> 16</td></tr></table></div>  <br/> The table above shows the combinations of beans and rice that can be purchased by a consumer. The opportunity cost of moving from K to L is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">17 units of rice  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 units of rice  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 units of beans  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 units of beans</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Moving from K to L, the change in beans is 20 units - 15 units = 5 units (an increase of 5 units). <br/>  <br/> The change in rice is 17 units - 19 units = -2 units (a decrease of 2 units). <br/>  <br/> The opportunity cost is the value of what is given up (the decrease in rice) to obtain something else (the increase in beans). Therefore, the opportunity cost of moving from K to L is 2 units of rice.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A necessary condition for specialization in an economy is the existence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a regulated market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a competitive market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequate capital  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a medium of exchange</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A necessary condition for specialization in an economy is the existence of a medium of exchange. Specialization refers to the concentration of the productive efforts of individuals and firms on a limited number of activities. It allows for the exchange of goods and services, which is facilitated by a medium of exchange. A medium of exchange is anything that is widely accepted in exchange for goods and services. In most countries, the medium of exchange is currency.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> A black market can occur when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> consumption of the commodity is restricted </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> prices are set by government above the equilibrium </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> prices are set by government below the equilibrium </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> supply is in excess of demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Black market is an unauthorized market transactions contrary to governmental regulations. When prices are set by government below the equilibrium, a black market will occur. Markets of this kind are often found when there are price or exchange controls or the restriction of trading to a list of authorized dealers.black is also known as parallel market.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the cost function C = 160 + 36Q, what is the average cost at 20 units of output? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦44.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦216.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦880.00 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦720.00  </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span> = 160 + 36Q  <br/>  = 160 + 36(20)  <br/>  = 160 + 720  <br/>  = 880  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TC<hr size=\"1\" />Q</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">880<hr size=\"1\" />20</td><td style=\"text-align:center;\"> = ₦44</td></tr></table></div> </div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A movement from M to T implies that there has been </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in supply  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in demand</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A movement from M to T implies that there is an increase in price. Hence,there is an increase in supply. </div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the diagram below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> When there is a change from T to N, it implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity supplied has increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity demanded has increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price has fallen  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply has increased </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphically, a movement from T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> N is a movement from S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> which implies an increase in supply or shift in supply.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> The diagram above shows the shifts in both demand and supply curve. What is the new equilibrium point after the shifts? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"> E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The new equilibrium is E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> since the movement is from D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.it is where the new supply and new demand curve meet which is E2.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm operating at full capacity will experience rising short-run total costs when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is a change in management </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices of its variable inputs rise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour productivity increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices of its variable inputs fall</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm producing with the excess capacity is producing at a rate of output below the point of minimum average total  cost and s firm producing above this point and is thus incurring costs higher than the minimum acheivable. A firm operating at full capacity will experience rising short-run total costs when prices of its variable inputs rise.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a textile factory, the cost of cotton used is a typical example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fixed cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a total cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a variable cost</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of cotton used is categorized under the variable cost because cotton quantity goes with the level of output.Cost of raw materials is a good example of variable cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an increase in the price of good X leads to an increase in the supply of good Y, X and Y are said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">composite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jointly supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jointly demanded</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two goods involved are jointly supplied.joint supply is where to or more commodities are supply from the same source.the production of one good means the production of the other good e.g petrol,engine oil,gas are produced from crude oil.</div>", "topic": "THE THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The marketing of agricultural commodities in Nigeria is hampered by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the abolition of marketing boards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of commodity exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of farmers' association </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of adequate storage facilities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Problems of agricultural development are: <br/> - land tenure system <br/> - inadequate finance or credit facilities <br/> - poor transportation systems <br/> - inadequate storage and processing <br/> - inadequate farm input <br/> -illteracy of the farmers <br/> - lack of basic amenities <br/> - lack of technical-know-how</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purpose of conducting a census is to enable a country to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plan her capital inflow and outflow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the growth rate of population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plan her growth and development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the optimum level of population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When census is conducted, then a country knows its population and finds out more about the people in the country. Census enables a country to know the size of its population, the composition of its population, and the distribution of its population.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Maximum wage legislation seeks to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fix wages above the equilibrium wage rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deter employers from exploiting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure an upper limit to the wage payable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">set wages below the equilibrium wage rate.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A maximum wage means that for specified industries, jobs, wages cannot exceed a certain level. They may be used to regulate labour markets where workers have excess monopoly power or in an unusual circumstance – such as a period of war. They are rarely used. Maximum Wages. To have any effect, a maximum wage (Max P) should be put below the equilibrium for that labour market (Pe).</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government's involvement in agricultural business in Nigeria is most manifested in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">procurement and distribution of fertilizers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of credit guarantee schemes for small-scale farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of farmer's cooperative societies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of farm settlements in each state of the federation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The role of government in Agriculture are: <br/> - Provision of credit facilities <br/> - Establishment of agricultural programmes <br/> - Provision of farm inputs <br/> - Provision of storage and processing facilities <br/> - Provision of basic amenities <br/> - Provision of effective transportation <br/> - Provision of pest and diseases control etc.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The downstream activities of oil companies in Nigeria involve</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">management of spillage and pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining and distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prospection and exploration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">off-shore drilling</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The downstream sector is the refining of petroleum crude oil and the processing and purifying of raw natural gas, as well as the marketing and distribution of products derived from crude oil and natural gas. </div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force in Nigeria falls between the ages of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18 and 60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 and 55</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 and 45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18 and 30</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force in Nigeria falls between the ages of 18 and 60. In the Public Service Rule, the allowable age for an appointee is 18 years and above. After employment, the employee can serve for a maximum of 35 years or cannot exceed 60 years in service.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of goods and services from the producers to the consumers is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the circular flow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the distribution chain</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Distribution chain is the routing of goods been produced by manufacturers or producer to the final consumer. The standard, correct and more economical distribution chain is Producer> Wholesaler> Retailer> Consumer.</div>", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION"}, {"id": "objective>Economics>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major cause of the slow pace of industrialization in Nigeria is inadequate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">skilled labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communal labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">landmass</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's infrastructure is underdeveloped and unreliable, which makes it difficult for businesses to operate efficiently. For example, power outages are common, and the transportation network is inadequate. This makes it difficult and expensive to transport goods and raw materials. <br/>  <br/> Other factors that contribute to the slow pace of industrialization in Nigeria include: <br/> -  Lack of skilled labor: Nigeria has a large population, but many people lack the skills needed for industrial jobs. This is due to a number of factors, including a shortage of schools and vocational training programs. <br/>  <br/> -  High cost of doing business: The cost of doing business in Nigeria is high, due to factors such as corruption, bureaucracy, and high taxes. This makes it difficult for businesses to compete and grow. <br/>  <br/> -  Political instability: Nigeria has a history of political instability, which can deter investors and make it difficult for businesses to plan for the future.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between birth and death rates of a given population is referred to as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">linear growth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortality rate  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertility rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural growth rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural growth rate is the difference between death rate and birth rate since both death and birth are natural occurrence.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import duty concessions on industrial inputs directly benefit the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">external sector </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial sector</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An approved manufacturer or producer is eligible for duty concession under Code 236 to Part 3 of the Customs Tariff at concessionary rates of Free Fiscal, Free Import Excise and 9% VAT. The concession is applicable on the raw materials, machinery, equipment and accessories which are used directly in the manufacture of the approved goods.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By advertising, a monopolistic competitive firm tries to shift its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply curve to the right </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply curve to the left </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve to the right  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve to the left </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Advertising is a communication activity used to influence potential buyers or others who can help the advertiser to reach defined goals. For firms, it is a selling cost incurred with the hope of increasing sales.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of the Central Bank in the economic development of Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">use cheques and bank drafts to facilitate business transactions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintain a stable price system </div>", "<div style=\"font-family:Cambria;font-size:17px;\">give short and medium-term loans to the public </div>", "<div style=\"font-family:Cambria;font-size:17px;\">give financial and technical advice to customer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Central Bank maintains a stable price system by preventing inflation, deflation, etcetera through its monetary/fiscal policies.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the maximum point of the total product curve of a firm, marginal revenue is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total product curve is an inverse moving catalogue of marginal revenue curve because marginal revenue is being realized through marginal cost. Thus, as total product curve moves to the peak, marginal revenue equals zero (relative to a horizontal axis) any further movement of total product curve make marginal revenue go negative.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which financial institution is charged with the formulation of monetary policies in Nigeria </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the Nigeria Deposit Insurance Corporation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Central Bank of Nigeria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Lagos Stock Exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Abuja Commodity Exchange</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Central bank is a financial institution which ultimately guarantees the liquidity of the banking system as a whole by setting interest rates for discounting and short-term bills of banking system. A central bank is able to exert a powerful influence over the size of money supply.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a open economy, the GNP is measured as  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C + I + G + (X-M)  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I + G </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I + G + M </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I + G + X</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An open economy is an economy that engages in international trade and the degree of openness can be measured by its imports or exports as a proportion of GDP. <br/> In an open economy, the GNP is measured as C + I + G + X – M, where C is consumption, I is investment, G is government spending, X is export and M is import.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distinction between perfect competition and monopolistic competition is that the latter is characterized by  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">homogeneity of product </div>", "<div style=\"font-family:Cambria;font-size:17px;\">product differentiation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a single market price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">many buyers and sellers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect market is a market in which there are large number of buyers and sellers, the good are identical, there is free entry and exit etc while a monopolistic competition is characterized by limited buyers and sellers, the goods are not identical,  there is no free entry and exit etc.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of non-bank financial institutions is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grant loans to banks </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manage investment portfolios for government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilize savings for investment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">receive deposits from banks</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Non Banking Financial Company supplement banks by providing the infrastructure to allocate surplus resources to individuals and companies with deficits. The most important function of the non-bank financial intermediaries is the transfer of funds from the savers to the investors. It also produces competition in the financial services industry. NBFC's keep their services flexible to meet the needs of specific client.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that Y = C + I and C = bY where b = 0.8, what is the multiplier? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">K = 1/ 1-MPC <br/>   <br/> MPC(b) =0.8 <br/>   <br/> K=1/1-0.8 <br/>  <br/>        = 1/0.2 <br/>  <br/>           =5</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above represents the short-run position of a monopolist. The product-maximizing  output is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q2  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The profit maximizing output is Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> because MC cuts MR from below. At that point, MC = MR i.e at Q2</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market provides business firms with the avenue to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">purchase capital equipment  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lease capital equipment  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obtain short-term funds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">obtain long-term funds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market is a market where buyers and sellers engage in trade of financial securities like bonds, stocks, etc. It serves as an avenue for business firms to obtain long-term funds. These funds can be used for purchasing capital equipment, expansion, or other long-term investments. The other options are not entirely correct because the capital market is not specifically for purchasing or leasing capital equipment, and it does not provide short-term funds.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">GDP differ from GNP because GDP</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emphasizes the final goods and services produced within the country of a particular period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emphasizes the goods and services produced within the country </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is inclusive of depreciation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emphasizes the market value of all final goods and services produced by nationals. </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">GDP is total output of goods and services produced within a country in a particular time period excluding net income from abroad.</div>", "topic": "NATIONAL INCOME : CONCEPT"}];
